import{c as i,Q as e,j as o,m as t}from"./chunks/framework.YkQPjC9l.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"chi-siamo.md","filePath":"chi-siamo.md","lastUpdated":1780253090000}'),n={name:"chi-siamo.md"};function r(l,a,s,c,d,u){return e(),o("div",null,[...a[0]||(a[0]=[t('<h3 id="cristian-trusca" tabindex="-1">Cristian Trusca <a class="header-anchor" href="#cristian-trusca" aria-label="Permalink to &quot;Cristian Trusca&quot;">​</a></h3><p>papà di Dominic con l&#39;esordio nel 2019 ha usato da subito Dexcom G5 e la terapia multi-iniettiva per passare dopo due anni a Dexcom G6 e Omnipod Eros, e ad oggi Ypsopump e Dexcom G6 con CamAps FX. Operatore sanitario da ormai 30 anni e appassionato di tecnologia si occupa di supporto/assistenza degli utenti e divulgazione della tecnologia nel gruppo Facebook italiano &quot;Diabete, glicemie a distanza e nuove tecnologie&quot; e nel gruppo rumeno &quot;CGM pentru Diabet&quot; nello spirito #WeAreNotWaiting.</p><h3 id="erika-manzoni" tabindex="-1">Erika Manzoni <a class="header-anchor" href="#erika-manzoni" aria-label="Permalink to &quot;Erika Manzoni&quot;">​</a></h3><p>ha ricevuto nel 2022, all&#39;età di 42 anni, la diagnosi di diabete autoimmune di tipo LADA e sin da subito si è affidata alla tecnologia utilizzando il sensore Libre 2 collegato con lo smartwatch. Nel tempo si è avvicinata sempre di più a questi strumenti, anche per rispondere a una necessità familiare: monitorare e supportare il figlio di 11 anni, affetto da una rara malattia genetica che comporta importanti problemi glicemici, soprattutto durante la scuola e l&#39;attività sportiva. Con l&#39;esperienza maturata negli anni, Erika ha imparato a conoscere e utilizzare diversi sensori, smartwatch e smartphone, mantenendo sempre la curiosità e la volontà di sperimentare nuove soluzioni tecnologiche. Condivide la propria esperienza cercando, per quanto possibile, di aiutare chi è alle prime esperienze ad orientarsi in un mondo digitale non sempre alla portata di tutti.</p><h3 id="luca-d-alba" tabindex="-1">Luca D&#39;Alba <a class="header-anchor" href="#luca-d-alba" aria-label="Permalink to &quot;Luca D&#39;Alba&quot;">​</a></h3><p>diabetico da quando aveva 12 anni, dopo 7 mesi di multi iniettiva è passato a micro MiniMed per 3 generazioni (640G con Enlite, 670G con Guardian 3 e ora 780G prima con Guardian 4 e ora con Simplera Sync). Insegna laboratorio di informatica dopo il diploma in tecnico informatico, nel frattempo studia all&#39;università ingegneria informatica</p><h3 id="maurizio-frijia" tabindex="-1">Maurizio Frijia <a class="header-anchor" href="#maurizio-frijia" aria-label="Permalink to &quot;Maurizio Frijia&quot;">​</a></h3><p>papà di Sofia, di Torino. Sofia ha esordito il 7 Luglio del 2014, per 2 anni ha usato le classiche penne per poi passare al sensore CGM Dexcom G4. In questo frangente ha cercato soluzioni per poter vedere le glicemie a distanza ed ha conosciuto Katiuscia Nosella, che li ha seguiti per la creazione di Nightscout. Grazie a questo sistema ha cercato nuove soluzioni per affrontare i limiti che nel tempo si presentavano. Nonostante non sia un classico programmatore, ma dotato di passione e forza di volontà, ha iniziato a capire come funzionava Nightscout e come si poteva sfruttare al meglio. Attualmente usa Dexcom G5 e riesce ad avere le glicemie su svariati supporti (smartwatch, pc, Alexa…) e Sofia può portare con sé anche solo lo smartwatch per le letture del sensore, senza telefono. Dal 2018 fa parte dell&#39;associazione A.G.D. Piemonte e Val D&#39;Aosta e assiste i nuovi esordi in merito alle nuove tecnologie.</p><h3 id="patrick-sonnerat" tabindex="-1">Patrick Sonnerat <a class="header-anchor" href="#patrick-sonnerat" aria-label="Permalink to &quot;Patrick Sonnerat&quot;">​</a></h3><p>papà di Andrea, esordio 2017, di Milano. Utilizzatore da subito di FSL1 ha cercato soluzioni per mantenere la promessa fatta a suo figlio: &quot;Farò di tutto per renderti questa malattia meno difficile&quot;. È partito da LimiTTer (con alcuni sviluppi in GitHub), passando da Sony SWR50 fino ad arrivare a MiaoMiao e Bubble nei quali si è specializzato e ha condiviso diverse soluzioni. Adesso usa Dexcom G7 (xDrip+) con Omnipod DASH e AAPS. Ingegnere elettronico e manager nel mondo della fabbricazione dei microchip, appassionato di tecnologia, è sempre alla ricerca di novità da condividere con tutti. Documentatore di Nightscout e AAPS, collabora attivamente con la comunità #WeAreNotWaiting per migliorare l&#39;accessibilità alle soluzioni open source ed altre.</p><h2 id="non-sono-piu-attivi-ma-non-li-dimentichiamo" tabindex="-1">Non sono più attivi ma non li dimentichiamo: <a class="header-anchor" href="#non-sono-piu-attivi-ma-non-li-dimentichiamo" aria-label="Permalink to &quot;Non sono più attivi ma non li dimentichiamo:&quot;">​</a></h2><h3 id="katiuscia-nosella" tabindex="-1">Katiuscia Nosella <a class="header-anchor" href="#katiuscia-nosella" aria-label="Permalink to &quot;Katiuscia Nosella&quot;">​</a></h3><p>mamma di Giulia, affetta da diabete di tipo 1 dall&#39;agosto 2014. Stendeva e aggiornava le guide per Nightscout dal 2015. Dall&#39;agosto 2017 amministra il gruppo Facebook Diabete, glicemie a distanza e nuove tecnologie, di cui è la fondatrice. All&#39;esordio di Giulia ha cominciato da subito a cercare soluzioni utili per alleggerire la gestione della malattia, imparando la conta dei carboidrati, acquistando FreeStyle Libre, la penna Pendiq e il sistema CGM Dexcom G4. Nel 2015 Giulia utilizza il microinfusore, prima Animas Vibe e ad oggi Tandem t:Slim X2 con Dexcom G5. Supportava ed assisteva gli utenti ispirandosi alla filosofia #WeAreNotWaiting di cui è sostenitrice.</p><h3 id="emiliano-manzo" tabindex="-1">Emiliano Manzo <a class="header-anchor" href="#emiliano-manzo" aria-label="Permalink to &quot;Emiliano Manzo&quot;">​</a></h3><p>papà di Amelia, diabetica tipo 1 dai suoi 22 mesi e celiaca, e marito di Elisa diabetica di tipo 1 dai 10 anni. Ricercatore nella vita, non appena ha conosciuto Elisa si è messo subito alla ricerca di quali fossero le migliori tecnologie per la gestione del diabete, ma è stato all&#39;esordio di Amelia che immediatamente si è messo a cercare in rete un modo per vedere le glicemie a distanza. La prima sera di ritorno dall&#39;ospedale ha creato il suo Nightscout e grazie all&#39;intervento di Katiuscia tutto ha funzionato da subito senza problemi. Ad Amelia è stato dato sin dal primo giorno fornito il microinfusoreMinimed 640G della Medtronic con sensore Guardian 2 abbinato, Elisa aveva già Medtronic Veo. Oggi Elisa utilizza con grande gioia il 670G di Medtronic in automatico. In questi anni ha cercato di capire al meglio tutto il funzionamento del sistema Medtronic. Dal 2017 gestivano il Blog potevaandarepeggio.com abbinato alla pagina Facebook dove si parlava di vita con diabete, celiachia, viaggi e ricette. Dal 2017 al 2019 ha partecipato a tutti i Congressi EASD e ATTD grazie al Diabetes Blogger Event di Roche. Questo gli ha permesso di tenersi aggiornato sulle ultime novità e entrare in contatto con la comunità internazionale #WeAreNotWaiting.</p><h3 id="paola-tranquillo" tabindex="-1">Paola Tranquillo <a class="header-anchor" href="#paola-tranquillo" aria-label="Permalink to &quot;Paola Tranquillo&quot;">​</a></h3><p>mamma di Camilla che oggi ha 17 anni. Il diabete è arrivato nella loro vita nel 2014. Ha iniziato ad usare il libre quando ancora non veniva passato dal sistema sanitario. Camilla non ha mai amato avere &quot;aggeggi&quot; addosso, ma pian piano ne ha capito l&#39;utilità. Ora usa il tandem tslim con il dexcom g6 abbinato. A nessuna delle due piacciono gli smartwatch, si accontentano dei telefoni. Paola è fan della tecnologia, che ha migliorato la qualità e la quantità di sonno notturno, ma non dimentica che il diabete si può gestire anche alla moda &quot;vecchia&quot; all&#39;occorrenza. La loro storia è raccontata anche nel libro &quot;Ricciolo Ribelle – dove sono finite le mie cellule beta?&quot;</p><h3 id="monica-lanzara" tabindex="-1">Monica Lanzara <a class="header-anchor" href="#monica-lanzara" aria-label="Permalink to &quot;Monica Lanzara&quot;">​</a></h3><p>ha il diabete di tipo 1 da quando aveva 14 anni. Ha iniziato con siringhe e insulina in boccette da miscelare. Ora è in terapia con penne e Frestyle Libre1, ma ha fatto pace con MisterD solo da quando, grazie al Miao Miao e alle app non ufficiali, è riuscita a trovare un modo per tenere sott&#39;occhio le glicemie. Trovare nella comunità diabetica online tante persone gentili e competenti le ha dato modo di capire quanto le persone possano fare per le altre e da qui la scelta di aiutare chiunque ne avesse bisogno.</p>',19)])])}const h=i(n,[["render",r]]);export{p as __pageData,h as default};
